import Foundation

// MARK: - AccountSelection

/// Which account a segment targets. `.currentlyActive` re-resolves at render time
/// so the segment tracks whichever Claude account is currently active.
public enum AccountSelection: Codable, Equatable, Hashable, Sendable {
    case currentlyActive
    case specific(AccountEmail)

    private enum CodingKeys: String, CodingKey {
        case kind, email
    }

    private enum Kind: String, Codable {
        case currentlyActive = "currently-active"
        case specific
    }

    public init(from decoder: Decoder) throws {
        let container = try decoder.container(keyedBy: CodingKeys.self)
        let kind = try container.decode(Kind.self, forKey: .kind)
        switch kind {
        case .currentlyActive:
            self = .currentlyActive
        case .specific:
            let email = try container.decode(AccountEmail.self, forKey: .email)
            self = .specific(email)
        }
    }

    public func encode(to encoder: Encoder) throws {
        var container = encoder.container(keyedBy: CodingKeys.self)
        switch self {
        case .currentlyActive:
            try container.encode(Kind.currentlyActive, forKey: .kind)
        case .specific(let email):
            try container.encode(Kind.specific, forKey: .kind)
            try container.encode(email, forKey: .email)
        }
    }
}

// MARK: - SegmentDisplay

/// Variant-dependent display options. `timeWindow` carries four independent
/// toggles plus the letter shown when `showLetter` is on; `payAsYouGo` has no
/// options — the rendered text is always "amount currency".
public enum SegmentDisplay: Codable, Equatable, Hashable, Sendable {
    case timeWindow(TimeWindowDisplay)
    case payAsYouGo

    private enum CodingKeys: String, CodingKey {
        case kind, timeWindow
    }

    private enum Kind: String, Codable {
        case timeWindow = "time-window"
        case payAsYouGo = "pay-as-you-go"
    }

    public init(from decoder: Decoder) throws {
        let container = try decoder.container(keyedBy: CodingKeys.self)
        let kind = try container.decode(Kind.self, forKey: .kind)
        switch kind {
        case .timeWindow:
            let tw = try container.decode(TimeWindowDisplay.self, forKey: .timeWindow)
            self = .timeWindow(tw)
        case .payAsYouGo:
            self = .payAsYouGo
        }
    }

    public func encode(to encoder: Encoder) throws {
        var container = encoder.container(keyedBy: CodingKeys.self)
        switch self {
        case .timeWindow(let tw):
            try container.encode(Kind.timeWindow, forKey: .kind)
            try container.encode(tw, forKey: .timeWindow)
        case .payAsYouGo:
            try container.encode(Kind.payAsYouGo, forKey: .kind)
        }
    }
}

public struct TimeWindowDisplay: Codable, Equatable, Hashable, Sendable {
    public var showDot: Bool
    public var showLetter: Bool
    public var letter: String
    public var showPercent: Bool
    public var showReset: Bool
    public var showVendorIcon: Bool

    public init(
        showDot: Bool = true,
        showLetter: Bool = true,
        letter: String = "",
        showPercent: Bool = true,
        showReset: Bool = true,
        showVendorIcon: Bool = false
    ) {
        self.showDot = showDot
        self.showLetter = showLetter
        self.letter = letter
        self.showPercent = showPercent
        self.showReset = showReset
        self.showVendorIcon = showVendorIcon
    }

    private enum CodingKeys: String, CodingKey {
        case showDot, showLetter, letter, showPercent, showReset, showVendorIcon
    }

    public init(from decoder: Decoder) throws {
        let c = try decoder.container(keyedBy: CodingKeys.self)
        showDot = try c.decode(Bool.self, forKey: .showDot)
        showLetter = try c.decode(Bool.self, forKey: .showLetter)
        letter = try c.decode(String.self, forKey: .letter)
        showPercent = try c.decode(Bool.self, forKey: .showPercent)
        showReset = try c.decode(Bool.self, forKey: .showReset)
        showVendorIcon = try c.decodeIfPresent(Bool.self, forKey: .showVendorIcon) ?? false
    }
}

// MARK: - MenuBarSegmentConfig

/// A user-configured menu bar segment: which metric to read (vendor/account/metric)
/// and how to display it. Persisted as JSON in UserDefaults.
public struct MenuBarSegmentConfig: Codable, Equatable, Hashable, Sendable, Identifiable {
    public let id: UUID
    public var vendor: Vendor
    public var account: AccountSelection
    public var metricName: String
    public var display: SegmentDisplay

    public init(
        id: UUID = UUID(),
        vendor: Vendor,
        account: AccountSelection,
        metricName: String,
        display: SegmentDisplay
    ) {
        self.id = id
        self.vendor = vendor
        self.account = account
        self.metricName = metricName
        self.display = display
    }
}

// MARK: - Default letters

/// Maps known metric names to their canonical menu bar letter. When unknown,
/// the first character of the metric name (uppercased) is used as default.
public enum MenuBarMetricLetter {
    private static let knownAbbreviations: [String: String] = [
        "5h sessions (all models)": "S",
        "Weekly (all models)": "W",
    ]

    public static func defaultLetter(for metricName: String) -> String {
        if let known = knownAbbreviations[metricName] {
            return known
        }
        return String(metricName.prefix(1)).uppercased()
    }
}

# Swift concurrency safety

## Never block the cooperative thread pool

Swift concurrency uses a fixed-size thread pool. Blocking calls starve other tasks.

- **Never** call `Process.waitUntilExit()` or any synchronous blocking API from an `async` context or inside an `actor`. Wrap blocking work in a `DispatchQueue` or `Task.detached` with a continuation.
- **Never** call `readDataToEndOfFile()` *after* `waitUntilExit()` — this deadlocks when the pipe buffer is full. Always read pipes *before* waiting for process termination.

```swift
// BAD — blocks the cooperative thread pool
func run() async throws -> Data {
    process.launch()
    let data = pipe.fileHandleForReading.readDataToEndOfFile() // deadlock risk
    process.waitUntilExit() // blocks a cooperative thread
    return data
}

// GOOD — async with continuation, read before wait
func run() async throws -> Data {
    return try await withCheckedThrowingContinuation { continuation in
        DispatchQueue.global().async {
            process.launch()
            let data = pipe.fileHandleForReading.readDataToEndOfFile()
            process.waitUntilExit()
            continuation.resume(returning: data)
        }
    }
}
```

## NSFormatter and other non-thread-safe Foundation types

`DateFormatter`, `ISO8601DateFormatter`, `NumberFormatter`, and similar `NSFormatter` subclasses are **not thread-safe**. If used from concurrent contexts:

- Make them `static let` on a dedicated serial queue, OR
- Create a new instance each time (acceptable for cold paths), OR
- Use Swift's `nonisolated(unsafe)` only if you prove single-threaded access.

Never share a formatter across threads without synchronization.

```swift
// BAD — data race
actor MyActor {
    private let formatter = ISO8601DateFormatter()
    func format(_ date: Date) -> String {
        formatter.string(from: date) // races if called from nonisolated context
    }
}

// GOOD — one instance per call (simple, safe)
func format(_ date: Date) -> String {
    let formatter = ISO8601DateFormatter()
    return formatter.string(from: date)
}

// GOOD — static on serial queue (reusable, safe)
enum DateFormatting {
    private static let queue = DispatchQueue(label: "formatter")
    private static let formatter = ISO8601DateFormatter()
    static func format(_ date: Date) -> String {
        queue.sync { formatter.string(from: date) }
    }
}
```

## Do not use `weak self` inside actors

Actors are reference types with their own isolation. Using `[weak self]` in closures inside an actor is unnecessary and misleading — the actor manages its own lifetime. Use `[self]` or capture nothing.

## Always add a timeout when launching external processes

When spawning a `Process`, always set a timeout mechanism (e.g., `DispatchSource.makeTimerSource` or `Task.sleep` + cancellation). A hung child process must not hang the app forever.

import SwiftUI
import AppKit
import AIUsagesTrackersLib

enum VendorBranding {
    struct Brand: Equatable, Sendable {
        let assetName: String
        let displayName: String
        let tintHex: String
    }

    static func brand(for vendor: Vendor) -> Brand? {
        switch vendor {
        case .claude:
            Brand(
                assetName: "claude-mark",
                displayName: "Claude Code",
                tintHex: "DA7756"
            )
        case .codex:
            Brand(
                assetName: "codex-mark",
                displayName: "Codex",
                tintHex: "10A37F"
            )
        default:
            nil
        }
    }

    static func displayName(for vendor: Vendor) -> String {
        brand(for: vendor)?.displayName ?? vendor.rawValue
    }

    static func tint(for vendor: Vendor) -> Color? {
        guard let tintHex = brand(for: vendor)?.tintHex else { return nil }
        return Color(hex: tintHex)
    }

    static func icon(for vendor: Vendor) -> NSImage? {
        guard let assetName = brand(for: vendor)?.assetName else { return nil }
        return loadTemplateImage(named: assetName)
    }

    /// Pixels of white halo added on each side around the vendor icon for legibility.
    static let iconGlowPadding: CGFloat = 3.0

    /// Returns a tinted, non-template copy of the vendor icon at the requested height.
    /// Uses the brand's `tintHex` as fill color and the template PDF as an alpha mask.
    /// A crisp white halo is produced by drawing a white silhouette at pixel offsets
    /// in all directions — no blur, so the icon stays sharp on any menu bar tint color.
    static func tintedNSImage(for vendor: Vendor, height: CGFloat) -> NSImage? {
        guard let template = icon(for: vendor),
              let brand = brand(for: vendor),
              let tintColor = NSColor(hex: brand.tintHex) else { return nil }
        let aspectRatio = template.size.height > 0
            ? template.size.width / template.size.height : 1
        let iconSize = NSSize(width: ceil(height * aspectRatio), height: ceil(height))
        let pad = Self.iconGlowPadding
        let canvasSize = NSSize(width: iconSize.width + pad * 2, height: iconSize.height + pad * 2)
        let iconRect = NSRect(x: pad, y: pad, width: iconSize.width, height: iconSize.height)

        let tinted = NSImage(size: iconSize)
        tinted.lockFocus()
        tintColor.setFill()
        NSRect(origin: .zero, size: iconSize).fill()
        template.draw(
            in: NSRect(origin: .zero, size: iconSize),
            from: .zero,
            operation: .destinationIn,
            fraction: 1.0
        )
        tinted.unlockFocus()

        let white = NSImage(size: iconSize)
        white.lockFocus()
        NSColor.white.setFill()
        NSRect(origin: .zero, size: iconSize).fill()
        template.draw(
            in: NSRect(origin: .zero, size: iconSize),
            from: .zero,
            operation: .destinationIn,
            fraction: 1.0
        )
        white.unlockFocus()

        let result = NSImage(size: canvasSize)
        result.lockFocus()
        // Draw the white silhouette at every surrounding pixel offset to build a crisp halo.
        for dx: CGFloat in [-2, -1, 0, 1, 2] {
            for dy: CGFloat in [-2, -1, 0, 1, 2] where !(dx == 0 && dy == 0) {
                white.draw(in: NSRect(
                    x: iconRect.minX + dx, y: iconRect.minY + dy,
                    width: iconRect.width, height: iconRect.height
                ))
            }
        }
        tinted.draw(in: iconRect)
        result.unlockFocus()
        result.isTemplate = false
        return result
    }

    private static func loadTemplateImage(named assetName: String) -> NSImage? {
        guard let url = Bundle.module.url(
            forResource: assetName,
            withExtension: "pdf",
            subdirectory: "VendorBranding"
        ), let image = NSImage(contentsOf: url) else {
            return nil
        }

        image.isTemplate = true
        return image
    }
}

struct VendorIconView: View {
    let vendor: Vendor
    var size: CGFloat = 14

    var body: some View {
        if let image = VendorBranding.icon(for: vendor),
           let tint = VendorBranding.tint(for: vendor) {
            Image(nsImage: image)
                .renderingMode(.template)
                .resizable()
                .scaledToFit()
                .frame(width: size, height: size)
                .foregroundStyle(tint)
                .accessibilityHidden(true)
        }
    }
}

struct VendorLabelView: View {
    let vendor: Vendor
    var iconSize: CGFloat = 14

    var body: some View {
        HStack(spacing: 6) {
            VendorIconView(vendor: vendor, size: iconSize)
            Text(VendorBranding.displayName(for: vendor))
        }
    }
}

private extension Color {
    init?(hex: String) {
        guard hex.count == 6, let value = Int(hex, radix: 16) else { return nil }

        let red = Double((value >> 16) & 0xFF) / 255.0
        let green = Double((value >> 8) & 0xFF) / 255.0
        let blue = Double(value & 0xFF) / 255.0

        self.init(red: red, green: green, blue: blue)
    }
}

private extension NSColor {
    convenience init?(hex: String) {
        guard hex.count == 6, let value = Int(hex, radix: 16) else { return nil }

        let red = CGFloat((value >> 16) & 0xFF) / 255.0
        let green = CGFloat((value >> 8) & 0xFF) / 255.0
        let blue = CGFloat(value & 0xFF) / 255.0

        self.init(red: red, green: green, blue: blue, alpha: 1.0)
    }
}

